var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"SPEAKER_JUNIOR_NULL_NULL","text":{"KOREA":"더듬이...... 너 그 복장은 대체 어떻게 된 거야?","JPN":"アホ毛……その服装はいったいどうしたの！？","ENG":"Antenna... What's with that outfit?","TWN":"小觸角……你那身衣服是怎麼回事？"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"RULER_JUNIOR_SPORTS_NULL","text":{"KOREA":"응! 어떤 선배가 빌려 줬어! 아카데미 공식 응원복이래!","JPN":"これね！　ある先輩が貸してくれたの！　アカデミー公式の応援団なんだって！","ENG":"Oh, I got it from a senior student! It's an official cheerleading uniform of the Academy!","TWN":"嗯！某個前輩借給我的！說是學院官方啦啦隊隊服！"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RULER_JUNIOR_SPORTS_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"RULER_JUNIOR_SPORTS_NULL","text":{"KOREA":"이걸 입고 응원단에 참가하면 개인점수를 준다나 봐!","JPN":"これを着て応援団として参加すれば個人点数がもらえるらしいよ！","ENG":"I can earn some individual points by wearing this uniform and joining the cheer squad!","TWN":"說是穿這身衣服加入啦啦隊的話會給個人分數呢！"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RULER_JUNIOR_SPORTS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SPEAKER_JUNIOR_NULL_NULL","text":{"KOREA":"오호...... 그런 방법이......","JPN":"ほう……そんな方法が……","ENG":"Oh... That's another way...","TWN":"哦吼……那種辦法……"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SPEAKER_JUNIOR_NULL_NULL","text":{"KOREA":"아니, 잠깐만?","JPN":"えっ、ちょっと待って！","ENG":"Hey! Hang on a second.","TWN":"不是，等等？"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SPEAKER_JUNIOR_NULL_NULL","text":{"KOREA":"널 알아보는 선배가 있었다고?","JPN":"スカイのことに気付く先輩がいたの？","ENG":"A senior student recognized you?","TWN":"你說有個前輩看見你了？"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RULER_JUNIOR_SPORTS_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"SPEAKER_JUNIOR_NULL_NULL","text":{"KOREA":"게다가 금방 잊어버리지도 않고?","JPN":"しかもすぐ忘れることもなく？","ENG":"And didn't forget about you right after that?","TWN":"而且還沒有馬上忘記？"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RULER_JUNIOR_SPORTS_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"RULER_JUNIOR_SPORTS_NULL","text":{"KOREA":"응. 여기, 음료수도 받았는걸.","JPN":"うん。ほら、飲み物ももらったもの。","ENG":"Yeah. Here, she even gave me a drink.","TWN":"嗯，這個，她還送了我飲料。"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RULER_JUNIOR_SPORTS_NULL","face":"UNIT_LAUGH"}}}},{"id":"L12_1","type":"dialog","speaker":"SPEAKER_JUNIOR_NULL_NULL","text":{"KOREA":"흥미롭네...... 다른 사람의 카운터 능력을 무효화하는 힘이라도 있는 걸까?","JPN":"興味深いぞ……他人のカウンター能力を無効化する力でもあるのか？","ENG":"Interesting... Could it be that she has an ability that negates other Counter's abilities?","TWN":"真有趣……難道她擁有讓其他人的制裁者能力失效的力量？"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"RULER_JUNIOR_SPORTS_NULL","face":"UNIT_LAUGH"}}}},{"id":"L13_1","type":"dialog","speaker":"SPEAKER_JUNIOR_NULL_NULL","text":{"KOREA":"만약 소원구슬로도 네 문제를 해결하지 못하면 그 선배를 찾아가 봐야겠어.","JPN":"もし願い玉でも君の問題を解決できなかったら、その先輩のところを訪ねてみるべきだね。","ENG":"If we can't solve your problem with the Wishing Ball, then we should go see that senior student.","TWN":"如果許願珠也不能解決你的問題，就去找那個前輩看看。"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RULER_JUNIOR_SPORTS_NULL","face":"UNIT_LAUGH"}}}},{"id":"L14_1","type":"dialog","speaker":"RULER_JUNIOR_SPORTS_NULL","text":{"KOREA":"그런데...... 케이시는 왜 저렇게 떨고 있는 거야?","JPN":"ところで……ケイシーはどうしてあんなに震えているの？","ENG":"Um, by the way, why is Kaci trembling like that?","TWN":"可是……卡西為什麼那麼緊張呢？"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RULER_JUNIOR_SPORTS_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L15_1","type":"dialog","speaker":"RULER_JUNIOR_SPORTS_NULL","text":{"KOREA":"누가 겁이라도 줬어?","JPN":"誰かに脅かされたの？","ENG":"Did someone scare her?","TWN":"難道有人嚇唬她了？"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RULER_JUNIOR_SPORTS_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"SPEAKER_JUNIOR_NULL_NULL","text":{"KOREA":"아, 그게 아니라 다음 경기가 전투 경기잖아.","JPN":"ああ、次の試合が戦闘試合でしょ。","ENG":"Oh, no. It's just that the next game is a combat match.","TWN":"啊，不是那樣的，下場比賽不是戰鬥比賽嘛。"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"RULER_JUNIOR_SPORTS_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"SPEAKER_JUNIOR_NULL_NULL","text":{"KOREA":"이번에는 추첨으로 선수를 뽑기로 했는데...... 케이시가 당첨되어 버렸거든.","JPN":"今回は抽選で選手を選ぶことになったんだけど……ケイシーが当たってしまったんだ。","ENG":"We drew straws to choose a player... and Kaci got the short straw.","TWN":"這次是通過抽籤選對手……卡西被抽中了。"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RULER_JUNIOR_SPORTS_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"아, 아무리 생각해도...... 이건 아닌 것 같아.","JPN":"ど、どう考えても……これはいけない気がする。","ENG":"I-I think... this is not right.","TWN":"不，不管怎麼想……我都覺得不行。"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"다른 사람으로 바꿔 달라고 하면 안 될까......?","JPN":"他の人に代わってほしいと言うのはダメ……？","ENG":"Can't we send someone else to play the game?","TWN":"可不可以要求換人……？"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SPEAKER_JUNIOR_NULL_NULL","text":{"KOREA":"아까 들었잖아. 이미 진행 위원회에 보고돼서 변경하기 어렵다고.","JPN":"さっき聞いたでしょ。もう進行委員会に報告しているから変更は難しいって。","ENG":"You heard them. They already sent the player list to the organizing committee, so it can't be changed.","TWN":"剛剛你不是聽到了嘛。已經報告給大賽委員會了，不能改了。"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L24_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"그, 그래도 어떻게든......","JPN":"で、でもそこをどうにか……","ENG":"B-but... There must be another way...","TWN":"那能不能再……"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"SPEAKER_JUNIOR_NULL_NULL","text":{"KOREA":"걱정 마. 네가 진짜로 이길 마음만 있다면 누가 상대라도 이길 수 있어.","JPN":"心配しないで。\\n心からスカイのために勝ちたいという気持ちさえあれば、誰が相手だって勝てるさ。","ENG":"Don't worry. If you really want to win, you will, no matter who the opponent is.","TWN":"別擔心，如果你真的想贏，不管對手是誰你都能贏。"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"하지만...... 저쪽 선수는 그...... 나이엘 블루스틸 선배라던데......","JPN":"でも、向こうの選手はあの……ナイエル・ブルースチール先輩だって……","ENG":"But... My opponent is... Naielle Bluesteel...","TWN":"可是……對方的選手是……奈爾前輩……"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L27_1","type":"dialog","speaker":"SPEAKER_JUNIOR_NULL_NULL","text":{"KOREA":"그, 그래......?","JPN":"そ、そう……？","ENG":"R-really?","TWN":"是，是嗎……？"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L28_1","type":"dialog","speaker":"SPEAKER_JUNIOR_NULL_NULL","text":{"KOREA":"논리적으로 생각해봤을 때 그건 좀 어려울지도......","JPN":"論理的に考えたら、それはさすがに厳しいかも……","ENG":"Then, logically speaking, your chances are not very high...","TWN":"從邏輯上來看的話，那個可能確實有點難……"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L30_1","type":"dialog","speaker":"RULER_JUNIOR_SPORTS_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RULER_JUNIOR_SPORTS_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"RULER_JUNIOR_SPORTS_NULL","text":{"KOREA":"괜찮아, 케이시.","JPN":"大丈夫、ケイシー。","ENG":"It's okay, Kaci.","TWN":"沒關係，卡西。"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RULER_JUNIOR_SPORTS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"하지만...... 내가 져서 우승을 못 하면...... 그러면 어떡해?","JPN":"でも、あたしが負けて優勝できなかったら……どうしよう？","ENG":"But... What if I lose? What if we don't win?","TWN":"可是……如果我輸了，沒能拿到優勝……那該怎麼辦？"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"RULER_JUNIOR_SPORTS_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"스카이의 문제를 해결해 주기로 약속했는데......","JPN":"スカイの問題を解決してあげるって約束したのに……","ENG":"I promised I'd solve your problem...","TWN":"我答應了要幫忙解決絲凱的問題……"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RULER_JUNIOR_SPORTS_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"약속을 못 지키게 되는 거잖아.","JPN":"約束を守れなくなっちゃう。","ENG":"If I lose, I won't be able to keep my promise.","TWN":"那樣就沒辦法遵守承諾了。"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RULER_JUNIOR_SPORTS_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"RULER_JUNIOR_SPORTS_NULL","text":{"KOREA":"괜찮아. 오히려 나 때문에 케이시가 다치면 더 슬플 거야.","JPN":"大丈夫だよ。むしろ私のせいでケイシーが怪我でもしたらもっと悲しくなるからね。","ENG":"It's okay, Kaci. I'll be sadder if you get hurt because of me.","TWN":"沒關係，如果卡西因為我受傷，我會更傷心的。"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RULER_JUNIOR_SPORTS_NULL","face":"UNIT_LAUGH"}}}},{"id":"L38_1","type":"dialog","speaker":"RULER_JUNIOR_SPORTS_NULL","text":{"KOREA":"그러니까 힘들 때는 바로 기권해도 돼.","JPN":"だから無理だと思った時はすぐ棄権してもいいよ。","ENG":"So if you don't want to fight, you can give up anytime you want.","TWN":"所以覺得不行的時候你可以馬上棄權。"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RULER_JUNIOR_SPORTS_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"저, 정말...... 그래도 괜찮아?","JPN":"ほ、本当に……それでもいいの？","ENG":"C-can I? Can I really give up?","TWN":"真，真的嗎……那樣也沒關係嗎？"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RULER_JUNIOR_SPORTS_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"RULER_JUNIOR_SPORTS_NULL","text":{"KOREA":"물론이지!","JPN":"もちろん！","ENG":"Of course you can!","TWN":"當然！"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RULER_JUNIOR_SPORTS_NULL","face":"UNIT_PRIDE"}}}},{"id":"L41_1","type":"dialog","speaker":"RULER_JUNIOR_SPORTS_NULL","text":{"KOREA":"경기 한 번 진다고 우승 못 한다는 법도 없잖아?","JPN":"試合で一回負けたからって優勝できないわけでもないし！","ENG":"Losing one game doesn't mean we can't be the final winners.","TWN":"有誰規定說輸一場比賽就不能拿冠軍了。"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RULER_JUNIOR_SPORTS_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"RULER_JUNIOR_SPORTS_NULL","text":{"KOREA":"날 믿어!","JPN":"私を信じて！","ENG":"Trust me!","TWN":"相信我！"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RULER_JUNIOR_SPORTS_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"......아냐. 나도 널 위해서 노력하고 싶어.","JPN":"……ううん、あたしもスカイのために頑張りたい。","ENG":"... No, I shouldn't give up. I want to do my best for you.","TWN":"……不是的，我也想為了你努力。"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"RULER_JUNIOR_SPORTS_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"무서운 것보다...... 친구가 더 소중하니까.","JPN":"怖いことより……友達のほうが大切だから。","ENG":"Although I'm afraid… friends are more important.","TWN":"雖然害怕……但我的朋友更重要。"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RULER_JUNIOR_SPORTS_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"나도...... 최선을 다할게!","JPN":"あたしも……全力でいく！","ENG":"I promise... I will do my best!","TWN":"我也……會全力以赴的！"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RULER_JUNIOR_SPORTS_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"RULER_JUNIOR_SPORTS_NULL","text":{"KOREA":"응! 나도 케이시를 열심히 응원하고 있을게!","JPN":"うん！　私もケイシーのことを一生懸命応援するから！","ENG":"Okay! I'll be cheering for you with all my heart!","TWN":"嗯！我也會為卡西全力加油的！"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RULER_JUNIOR_SPORTS_NULL","face":"UNIT_LAUGH"}}}}]`);export{e as default};